const DEFAULT_LANG = "en";

export function getStoredLang() {
  try {
    const v = localStorage.getItem("bitelyze_lang");
    if (v && STRINGS[v]) return v;
    if (v && LANGUAGES.find(l => l.code === v)) return v; // valid code, no full translation yet
  } catch (e) {}
  return DEFAULT_LANG;
}

export function setStoredLang(code) {
  try { localStorage.setItem("bitelyze_lang", code); } catch (e) {}
}

// Translate a single key. Falls back to English, then to the key itself.
export function translate(key, lang) {
  const dict = STRINGS[lang] || STRINGS[DEFAULT_LANG];
  if (dict && dict[key]) return dict[key];
  if (STRINGS[DEFAULT_LANG][key]) return STRINGS[DEFAULT_LANG][key];
  return key;
}

// Helper that returns a t(key) function bound to a language.
export function makeT(lang) {
  return (key) => translate(key, lang);
}
